from lxml import etree
W='{http://schemas.openxmlformats.org/wordprocessingml/2006/main}'
tree = etree.parse('workdir_check/word/document.xml')
root = tree.getroot()
body = root.find(W+'body')
# Find paragraphs that are entirely inserted (pPr/rPr/ins present) -> new paragraphs
def ptext(p):
    return ''.join((t.text or '') for t in p.iter(W+'t')) + ''.join((t.text or '') for t in p.iter(W+'delText'))
new_paras=[]
for p in body.findall(W+'p'):
    pPr = p.find(W+'pPr')
    if pPr is not None:
        rPr = pPr.find(W+'rPr')
        if rPr is not None and rPr.find(W+'ins') is not None:
            new_paras.append(ptext(p))
print('Wholly-new inserted paragraphs:', len(new_paras))
for t in new_paras:
    print('---')
    print(t[:160])
""}

