from lxml import etree
W='{http://schemas.openxmlformats.org/wordprocessingml/2006/main}'
tree = etree.parse('workdir_check/word/document.xml')
body = tree.getroot().find(W+'body')
def render(p):
    out=[]
    for child in p:
        if child.tag==W+'r':
            t=child.find(W+'t'); dt=child.find(W+'delText')
            txt=(t.text if t is not None else '') or (dt.text if dt is not None else '')
            if txt: out.append(txt)
        elif child.tag==W+'ins':
            for r in child.findall(W+'r'):
                t=r.find(W+'t'); txt=t.text if t is not None else ''
                if txt: out.append('['+txt+']')
        elif child.tag==W+'del':
            for r in child.findall(W+'r'):
                t=r.find(W+'delText'); txt=t.text if t is not None else ''
                if txt: out.append('{-'+txt+'-}')
    return ''.join(out)
ps=body.findall(W+'p')
# find paragraphs containing key markers
import re
for p in ps:
    r=render(p)
    if 'Twelve Dollars' in r or 'twenty-one (21) calendar days from' in r or 'approximately seven (7) months' in r or 'states of Oregon and Washington' in r or 'neutral employment reference' in r:
        print('---')
        print(r[:400])
""}

